#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Check for sensor timeout first */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT || input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE) {
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        output.timed_out = true;
    } else if (input.kind == CONTROLLER_INPUT_NONE) {
        /* Poll for stale sensor data - check timeout */
        uint32_t elapsed_ms = 0;
        if (controller->last_valid_sensor_ms > input.now_ms) {
            /* Handle wrap-around */
            elapsed_ms = input.now_ms - controller->last_valid_sensor_ms;
        } else {
            elapsed_ms = input.now_ms - controller->last_valid_sensor_ms;
        }

        if (controller->has_valid_sensor && elapsed_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            /* Stale sensor data - fail safe */
            controller_set_safe_off(controller);
            output.timed_out = true;
        } else {
            /* No new input, hold previous state */
            controller->state = CONTROLLER_STATE_HOLDING;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.heater_on = controller->heater_on;
            output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);
            return output;
        }
    } else if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        int temp = input.temperature_c;

        /* Check for stale data on temperature input */
        if (controller->last_valid_sensor_ms > 0 && input.now_ms > controller->last_valid_sensor_ms) {
            uint32_t elapsed = input.now_ms - controller->last_valid_sensor_ms;
            if (elapsed > CONTROLLER_SENSOR_TIMEOUT_MS && controller->last_valid_sensor_ms != 0) {
                /* This shouldn't happen on fresh temperature input, but handle it */
            }
        }

        /* Control policy based on temperature */
        if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* TEMP < 47: turn heater ON */
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        } else if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* TEMP > 52: turn heater OFF, safe state */
            controller_set_safe_off(controller);
        } else if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < 50) {
            /* 47 <= TEMP < 50: hold previous safe actuator state */
            controller->state = CONTROLLER_STATE_HOLDING;
        } else if (temp >= 50 && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* 50 <= TEMP <= 52: check for rising temperature */
            bool rising = false;
            if (controller->last_temperature_c != 0) {
                rising = (input.temperature_c > controller->last_temperature_c);
            }

            if (rising) {
                /* Rising temperature near upper band: turn heater OFF early, HOLDING state */
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            } else {
                /* Not rising: hold previous safe actuator state */
                controller->state = CONTROLLER_STATE_HOLDING;
            }
        }
    }

    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}

